# FastAPI middleware to add deprecation headers for deprecated model/prompt versions
from fastapi import Request, Response
from datetime import date

DEPRECATED_VERSIONS = {
    "prompt-summarization-v2": {
        "sunset": date(2026, 10, 1),
        "successor": "/api/v3/summarize",
    },
    "gpt-4-0314": {
        "sunset": date(2026, 9, 30),
        "successor": "gpt-4o",
    },
}

async def deprecation_header_middleware(request: Request, call_next):
    response: Response = await call_next(request)

    # Check if request uses a deprecated version
    model_version = request.headers.get("X-Model-Version") or request.query_params.get("model_version")
    prompt_version = request.headers.get("X-Prompt-Version")

    for version_key in [model_version, prompt_version]:
        if version_key and version_key in DEPRECATED_VERSIONS:
            info = DEPRECATED_VERSIONS[version_key]
            response.headers["Deprecation"] = "true"
            response.headers["Sunset"] = info["sunset"].strftime("%a, %d %b %Y 23:59:59 GMT")
            response.headers["Link"] = f'<{info["successor"]}>; rel="successor-version"'

    return response
